#[async_trait]
impl SnapshotStore for PostgresSnapshotStore {
    async fn save(&self, snapshot: &Snapshot) -> Result<()> {
        let query = format!(
            "INSERT INTO {} (aggregate_id, aggregate_type, version, state, created_at) 
             VALUES ($1, $2, $3, $4, $5) 
             ON CONFLICT (aggregate_id) DO UPDATE SET 
             version = EXCLUDED.version, state = EXCLUDED.state, created_at = EXCLUDED.created_at",
            self.table_name
        );

        sqlx::query(&query)
            .bind(snapshot.aggregate_id)
            .bind(&snapshot.aggregate_type)
            .bind(snapshot.version)
            .bind(&snapshot.state)
            .bind(snapshot.created_at)
            .execute(&self.pool)
            .await?;

        Ok(())
    }

    async fn load(&self, aggregate_id: Uuid) -> Result<Option<Snapshot>> {
        let query = format!(
            "SELECT * FROM {} WHERE aggregate_id = $1",
            self.table_name
        );

        let snapshot = sqlx::query_as::<_, Snapshot>(&query)
            .bind(aggregate_id)
            .fetch_optional(&self.pool)
            .await?;

        Ok(snapshot)
    }

    async fn delete(&self, aggregate_id: Uuid) -> Result<()> {
        let query = format!(
            "DELETE FROM {} WHERE aggregate_id = $1",
            self.table_name
        );

        sqlx::query(&query)
            .bind(aggregate_id)
            .execute(&self.pool)
            .await?;

        Ok(())
    }
}

