/// Configuration for when to create snapshots
#[derive(Debug, Clone)]
pub struct SnapshotStrategy {
    /// Whether snapshots are enabled
    pub enabled: bool,
    /// Create snapshot every N events
    pub every_n_events: u32,
    /// Maximum age before creating new snapshot
    pub max_age_seconds: Option<u64>,
    /// Storage backend (e.g., "postgres", "redis")
    pub storage: Option<String>,
}

impl Default for SnapshotStrategy {
    fn default() -> Self {
        Self {
            enabled: true,
            every_n_events: 100,
            max_age_seconds: Some(86400), // 24 hours
            storage: None,
        }
    }
}

impl SnapshotStrategy {
    /// Create a new snapshot strategy
    pub fn new(enabled: bool, every_n_events: u32) -> Self {
        Self {
            enabled,
            every_n_events,
            max_age_seconds: None,
            storage: None,
        }
    }

    /// Set max age before new snapshot
    pub fn with_max_age(mut self, seconds: u64) -> Self {
        self.max_age_seconds = Some(seconds);
        self
    }

    /// Set storage backend
    pub fn with_storage(mut self, storage: impl Into<String>) -> Self {
        self.storage = Some(storage.into());
        self
    }

    /// Check if a snapshot should be created
    pub fn should_snapshot(&self, current_version: i64, last_snapshot_version: i64) -> bool {
        self.enabled && (current_version - last_snapshot_version) as u32 >= self.every_n_events
    }
}

